import React, { useEffect, useMemo, useState } from 'react';
import {
  BadgeCheck,
  Briefcase,
  Building2,
  CheckCircle2,
  Filter,
  Globe,
  Mail,
  Phone,
  Search,
  ToggleLeft,
  ToggleRight,
  XCircle,
} from 'lucide-react';
import { format } from 'date-fns';
import {
  getAllCompanies,
  getAllJobs,
  toggleCompanyStatus,
  toggleJobStatus,
} from '../services/api';

const sectionCardStyle = {
  backgroundColor: 'white',
  padding: '24px',
  borderRadius: '16px',
  boxShadow: '0 8px 24px rgba(15, 23, 42, 0.08)',
  border: '1px solid #e5e7eb',
};

const actionButtonStyle = {
  display: 'inline-flex',
  alignItems: 'center',
  justifyContent: 'center',
  gap: '8px',
  padding: '10px 14px',
  borderRadius: '10px',
  border: 'none',
  cursor: 'pointer',
  fontSize: '13px',
  fontWeight: '600',
};

const Companies = () => {
  const [companies, setCompanies] = useState([]);
  const [jobs, setJobs] = useState([]);
  const [selectedCompanyId, setSelectedCompanyId] = useState(null);
  const [searchTerm, setSearchTerm] = useState('');
  const [companyStatusFilter, setCompanyStatusFilter] = useState('all');
  const [jobStatusFilter, setJobStatusFilter] = useState('all');
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');

  useEffect(() => {
    const loadData = async () => {
      setLoading(true);
      setError('');

      try {
        const [companiesResponse, jobsResponse] = await Promise.all([
          getAllCompanies(),
          getAllJobs(),
        ]);

        const nextCompanies = companiesResponse.data || [];
        setCompanies(nextCompanies);
        setJobs(jobsResponse.data || []);
        if (nextCompanies.length > 0) {
          setSelectedCompanyId(nextCompanies[0].id);
        }
      } catch (err) {
        setError(err.response?.data?.message || err.message || 'Unable to load company management data.');
      } finally {
        setLoading(false);
      }
    };

    loadData();
  }, []);

  const handleToggleCompanyStatus = async (companyId, currentStatus) => {
    try {
      const response = await toggleCompanyStatus(companyId, !currentStatus);
      const updatedCompany = response.data;
      setCompanies((prev) =>
        prev.map((company) => (company.id === companyId ? updatedCompany : company))
      );
    } catch (err) {
      setError(err.response?.data?.message || err.message || 'Unable to update company status.');
    }
  };

  const handleToggleJobStatus = async (jobId, currentStatus) => {
    try {
      const response = await toggleJobStatus(jobId, currentStatus !== 'APPROVED');
      const updatedJob = response.data;
      setJobs((prev) => prev.map((job) => (job.id === jobId ? updatedJob : job)));
    } catch (err) {
      setError(err.response?.data?.message || err.message || 'Unable to update job status.');
    }
  };

  const filteredCompanies = useMemo(() => {
    return companies.filter((company) => {
      const matchesSearch =
        company.companyName?.toLowerCase().includes(searchTerm.toLowerCase()) ||
        company.industry?.toLowerCase().includes(searchTerm.toLowerCase()) ||
        company.contactPerson?.toLowerCase().includes(searchTerm.toLowerCase());

      const matchesFilter =
        companyStatusFilter === 'all' ||
        (companyStatusFilter === 'approved' && company.active) ||
        (companyStatusFilter === 'pending' && company.registrationStatus === 'PENDING') ||
        (companyStatusFilter === 'rejected' && company.registrationStatus === 'REJECTED');

      return matchesSearch && matchesFilter;
    });
  }, [companies, companyStatusFilter, searchTerm]);

  const selectedCompany =
    filteredCompanies.find((company) => company.id === selectedCompanyId) || filteredCompanies[0] || null;

  const companyJobs = useMemo(() => {
    return jobs.filter((job) => {
      const matchesCompany = !selectedCompany || job.companyId === selectedCompany.id;
      const matchesStatus =
        jobStatusFilter === 'all' ||
        (jobStatusFilter === 'approved' && job.status === 'APPROVED') ||
        (jobStatusFilter === 'pending' && job.status === 'PENDING') ||
        (jobStatusFilter === 'rejected' && job.status === 'REJECTED');
      return matchesCompany && matchesStatus;
    });
  }, [jobStatusFilter, jobs, selectedCompany]);

  return (
    <div style={{ padding: '20px', backgroundColor: '#f8fafc' }}>
      <div style={{ marginBottom: '32px' }}>
        <h1 style={{ fontSize: '32px', fontWeight: 'bold', color: '#111827', marginBottom: '8px' }}>
          Company And Job Approvals
        </h1>
        <p style={{ color: '#6b7280' }}>
          Approve registered companies, review submitted jobs, and control what students can see.
        </p>
      </div>

      {error && (
        <div
          style={{
            marginBottom: '24px',
            borderRadius: '12px',
            border: '1px solid #fecaca',
            backgroundColor: '#fef2f2',
            padding: '16px',
            color: '#b91c1c',
            fontSize: '14px',
          }}
        >
          {error}
        </div>
      )}

      <div
        style={{
          display: 'grid',
          gridTemplateColumns: 'repeat(auto-fit, minmax(220px, 1fr))',
          gap: '16px',
          marginBottom: '24px',
        }}
      >
        <div style={sectionCardStyle}>
          <div style={{ fontSize: '13px', color: '#475569', marginBottom: '10px', fontWeight: '600' }}>
            Registered Companies
          </div>
          <div style={{ fontSize: '30px', fontWeight: '700', color: '#111827' }}>{companies.length}</div>
        </div>
        <div style={sectionCardStyle}>
          <div style={{ fontSize: '13px', color: '#475569', marginBottom: '10px', fontWeight: '600' }}>
            Approved Companies
          </div>
          <div style={{ fontSize: '30px', fontWeight: '700', color: '#111827' }}>
            {companies.filter((company) => company.active).length}
          </div>
        </div>
        <div style={sectionCardStyle}>
          <div style={{ fontSize: '13px', color: '#475569', marginBottom: '10px', fontWeight: '600' }}>
            Total Job Posts
          </div>
          <div style={{ fontSize: '30px', fontWeight: '700', color: '#111827' }}>{jobs.length}</div>
        </div>
        <div style={sectionCardStyle}>
          <div style={{ fontSize: '13px', color: '#475569', marginBottom: '10px', fontWeight: '600' }}>
            Pending Job Approvals
          </div>
          <div style={{ fontSize: '30px', fontWeight: '700', color: '#111827' }}>
            {jobs.filter((job) => job.status === 'PENDING').length}
          </div>
        </div>
      </div>

      <div style={{ ...sectionCardStyle, marginBottom: '24px' }}>
        <div style={{ display: 'flex', flexDirection: 'column', gap: '16px' }}>
          <div style={{ position: 'relative' }}>
            <Search
              style={{
                position: 'absolute',
                left: '12px',
                top: '50%',
                transform: 'translateY(-50%)',
                height: '16px',
                width: '16px',
                color: '#9ca3af',
              }}
            />
            <input
              type="text"
              placeholder="Search companies by name, industry, or contact person..."
              value={searchTerm}
              onChange={(e) => setSearchTerm(e.target.value)}
              style={{
                width: '100%',
                padding: '10px 12px 10px 44px',
                border: '1px solid #d1d5db',
                borderRadius: '10px',
                fontSize: '14px',
                outline: 'none',
              }}
            />
          </div>

          <div style={{ display: 'flex', gap: '10px', flexWrap: 'wrap' }}>
            <select
              value={companyStatusFilter}
              onChange={(e) => setCompanyStatusFilter(e.target.value)}
              style={{
                padding: '10px 12px',
                border: '1px solid #d1d5db',
                borderRadius: '10px',
                fontSize: '14px',
                outline: 'none',
              }}
            >
              <option value="all">All Companies</option>
              <option value="approved">Approved Companies</option>
              <option value="pending">Pending Companies</option>
              <option value="rejected">Rejected Companies</option>
            </select>

            <select
              value={jobStatusFilter}
              onChange={(e) => setJobStatusFilter(e.target.value)}
              style={{
                padding: '10px 12px',
                border: '1px solid #d1d5db',
                borderRadius: '10px',
                fontSize: '14px',
                outline: 'none',
              }}
            >
              <option value="all">All Jobs</option>
              <option value="approved">Approved Jobs</option>
              <option value="pending">Pending Jobs</option>
              <option value="rejected">Rejected Jobs</option>
            </select>

            <div
              style={{
                ...actionButtonStyle,
                backgroundColor: '#e2e8f0',
                color: '#334155',
              }}
            >
              <Filter size={16} />
              Filters Active
            </div>
          </div>
        </div>
      </div>

      <div
        style={{
          display: 'grid',
          gridTemplateColumns: 'minmax(0, 1.1fr) minmax(0, 0.9fr)',
          gap: '24px',
          alignItems: 'start',
        }}
      >
        <div style={sectionCardStyle}>
          <div style={{ marginBottom: '18px' }}>
            <h2 style={{ margin: 0, fontSize: '24px', fontWeight: '700', color: '#111827' }}>
              Registered Companies
            </h2>
            <p style={{ margin: '8px 0 0 0', color: '#6b7280', fontSize: '14px' }}>
              Enable a company first, then approve its posted jobs.
            </p>
          </div>

          <div style={{ display: 'flex', flexDirection: 'column', gap: '14px' }}>
            {!loading && filteredCompanies.length === 0 && (
              <div
                style={{
                  padding: '20px',
                  borderRadius: '12px',
                  backgroundColor: '#f8fafc',
                  border: '1px dashed #cbd5e1',
                  color: '#64748b',
                  fontSize: '14px',
                }}
              >
                No companies found for the current filters.
              </div>
            )}

            {filteredCompanies.map((company) => (
              <button
                key={company.id}
                type="button"
                onClick={() => setSelectedCompanyId(company.id)}
                style={{
                  textAlign: 'left',
                  width: '100%',
                  borderRadius: '14px',
                  border: company.id === selectedCompany?.id ? '1px solid #60a5fa' : '1px solid #e2e8f0',
                  backgroundColor: company.id === selectedCompany?.id ? '#eff6ff' : '#f8fafc',
                  padding: '18px',
                  cursor: 'pointer',
                }}
              >
                <div style={{ display: 'flex', justifyContent: 'space-between', gap: '12px' }}>
                  <div>
                    <div style={{ display: 'flex', alignItems: 'center', gap: '8px', marginBottom: '8px' }}>
                      <Building2 size={18} color="#2563eb" />
                      <span style={{ fontSize: '17px', fontWeight: '700', color: '#111827' }}>
                        {company.companyName}
                      </span>
                    </div>
                    <div style={{ fontSize: '14px', color: '#475569', marginBottom: '6px' }}>
                      {company.industry || 'Industry not specified'}
                    </div>
                    <div style={{ fontSize: '13px', color: '#64748b' }}>
                      {company.contactPerson || 'No contact person'} • {company.jobsCount || 0} jobs posted
                    </div>
                  </div>

                  <span
                    style={{
                      display: 'inline-flex',
                      alignItems: 'center',
                      alignSelf: 'flex-start',
                      padding: '6px 10px',
                      borderRadius: '9999px',
                      fontSize: '12px',
                      fontWeight: '700',
                      backgroundColor: company.active ? '#dcfce7' : company.registrationStatus === 'REJECTED' ? '#fee2e2' : '#fef3c7',
                      color: company.active ? '#166534' : company.registrationStatus === 'REJECTED' ? '#991b1b' : '#92400e',
                    }}
                  >
                    {company.registrationStatus || (company.active ? 'APPROVED' : 'PENDING')}
                  </span>
                </div>

                <div style={{ display: 'flex', flexWrap: 'wrap', gap: '12px', marginTop: '14px', fontSize: '13px', color: '#475569' }}>
                  {company.website && (
                    <span style={{ display: 'inline-flex', alignItems: 'center', gap: '6px' }}>
                      <Globe size={14} />
                      Website
                    </span>
                  )}
                  {company.contactEmail && (
                    <span style={{ display: 'inline-flex', alignItems: 'center', gap: '6px' }}>
                      <Mail size={14} />
                      {company.contactEmail}
                    </span>
                  )}
                  {company.contactPhone && (
                    <span style={{ display: 'inline-flex', alignItems: 'center', gap: '6px' }}>
                      <Phone size={14} />
                      {company.contactPhone}
                    </span>
                  )}
                </div>

                <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginTop: '16px' }}>
                  <div style={{ fontSize: '13px', color: '#64748b' }}>
                    Registered:{' '}
                    {company.registrationDate ? format(new Date(company.registrationDate), 'MMM dd, yyyy') : 'N/A'}
                  </div>

                  <button
                    type="button"
                    onClick={(event) => {
                      event.stopPropagation();
                      handleToggleCompanyStatus(company.id, company.active);
                    }}
                    style={{
                      background: 'none',
                      border: 'none',
                      cursor: 'pointer',
                      color: company.active ? '#059669' : '#64748b',
                      padding: '4px',
                    }}
                    title={company.active ? 'Disable company' : 'Enable company'}
                  >
                    {company.active ? (
                      <ToggleRight style={{ height: '22px', width: '22px' }} />
                    ) : (
                      <ToggleLeft style={{ height: '22px', width: '22px' }} />
                    )}
                  </button>
                </div>
              </button>
            ))}
          </div>
        </div>

        <div style={sectionCardStyle}>
          <div style={{ marginBottom: '18px' }}>
            <h2 style={{ margin: 0, fontSize: '24px', fontWeight: '700', color: '#111827' }}>
              {selectedCompany ? `${selectedCompany.companyName} Jobs` : 'Posted Jobs'}
            </h2>
            <p style={{ margin: '8px 0 0 0', color: '#6b7280', fontSize: '14px' }}>
              Review each submitted role and approve only the jobs that should appear in the student UI.
            </p>
          </div>

          {selectedCompany && (
            <div
              style={{
                marginBottom: '18px',
                padding: '16px',
                borderRadius: '14px',
                backgroundColor: '#f8fafc',
                border: '1px solid #e2e8f0',
              }}
            >
              <div style={{ fontSize: '18px', fontWeight: '700', color: '#111827', marginBottom: '6px' }}>
                {selectedCompany.companyName}
              </div>
              <div style={{ fontSize: '14px', color: '#475569', marginBottom: '12px' }}>
                {selectedCompany.industry || 'Industry not specified'}
              </div>
              <div style={{ display: 'flex', gap: '10px', flexWrap: 'wrap' }}>
                <span
                  style={{
                    display: 'inline-flex',
                    alignItems: 'center',
                    gap: '6px',
                    padding: '8px 12px',
                    borderRadius: '9999px',
                    backgroundColor: selectedCompany.active ? '#dcfce7' : '#fef3c7',
                    color: selectedCompany.active ? '#166534' : '#92400e',
                    fontSize: '13px',
                    fontWeight: '600',
                  }}
                >
                  <BadgeCheck size={14} />
                  Company {selectedCompany.active ? 'Enabled' : 'Pending'}
                </span>
                <span
                  style={{
                    display: 'inline-flex',
                    alignItems: 'center',
                    gap: '6px',
                    padding: '8px 12px',
                    borderRadius: '9999px',
                    backgroundColor: '#e0f2fe',
                    color: '#0f766e',
                    fontSize: '13px',
                    fontWeight: '600',
                  }}
                >
                  <Briefcase size={14} />
                  {companyJobs.length} filtered jobs
                </span>
              </div>
            </div>
          )}

          <div style={{ display: 'flex', flexDirection: 'column', gap: '14px' }}>
            {!loading && companyJobs.length === 0 && (
              <div
                style={{
                  padding: '20px',
                  borderRadius: '12px',
                  backgroundColor: '#f8fafc',
                  border: '1px dashed #cbd5e1',
                  color: '#64748b',
                  fontSize: '14px',
                }}
              >
                No jobs found for the selected company and filters.
              </div>
            )}

            {companyJobs.map((job) => {
              const isApproved = job.status === 'APPROVED';
              const isRejected = job.status === 'REJECTED';

              return (
                <div
                  key={job.id}
                  style={{
                    borderRadius: '14px',
                    border: '1px solid #e2e8f0',
                    backgroundColor: '#f8fafc',
                    padding: '18px',
                  }}
                >
                  <div style={{ display: 'flex', justifyContent: 'space-between', gap: '12px', marginBottom: '12px' }}>
                    <div>
                      <div style={{ fontSize: '18px', fontWeight: '700', color: '#111827', marginBottom: '6px' }}>
                        {job.title}
                      </div>
                      <div style={{ fontSize: '13px', color: '#64748b' }}>
                        Posted {job.createdAt ? format(new Date(job.createdAt), 'MMM dd, yyyy') : 'recently'}
                      </div>
                    </div>
                    <span
                      style={{
                        display: 'inline-flex',
                        alignItems: 'center',
                        alignSelf: 'flex-start',
                        padding: '6px 10px',
                        borderRadius: '9999px',
                        fontSize: '12px',
                        fontWeight: '700',
                        backgroundColor: isApproved ? '#dcfce7' : isRejected ? '#fee2e2' : '#fef3c7',
                        color: isApproved ? '#166534' : isRejected ? '#991b1b' : '#92400e',
                      }}
                    >
                      {job.status}
                    </span>
                  </div>

                  <div style={{ display: 'grid', gridTemplateColumns: 'repeat(2, minmax(0, 1fr))', gap: '12px', marginBottom: '14px' }}>
                    <div style={{ fontSize: '14px', color: '#334155' }}>
                      <strong>Positions:</strong> {job.positions}
                    </div>
                    <div style={{ fontSize: '14px', color: '#334155' }}>
                      <strong>Package:</strong> {job.salaryPackage}
                    </div>
                    <div style={{ fontSize: '14px', color: '#334155' }}>
                      <strong>Location:</strong> {job.location}
                    </div>
                    <div style={{ fontSize: '14px', color: '#334155' }}>
                      <strong>Min CGPA:</strong> {job.minimumCgpa ?? 'Not specified'}
                    </div>
                  </div>

                  {(job.applicationLink || job.jdFileUrl) && (
                    <div style={{ display: 'flex', gap: '10px', flexWrap: 'wrap', marginBottom: '14px' }}>
                      {job.applicationLink && (
                        <a
                          href={job.applicationLink}
                          target="_blank"
                          rel="noopener noreferrer"
                          style={{
                            display: 'inline-flex',
                            alignItems: 'center',
                            gap: '6px',
                            padding: '8px 12px',
                            borderRadius: '9999px',
                            backgroundColor: '#dbeafe',
                            color: '#1d4ed8',
                            fontSize: '13px',
                            fontWeight: '600',
                            textDecoration: 'none',
                          }}
                        >
                          <Globe size={14} />
                          Job Link
                        </a>
                      )}
                      {job.jdFileUrl && (
                        <a
                          href={`http://localhost:8080/${job.jdFileUrl}`}
                          target="_blank"
                          rel="noopener noreferrer"
                          style={{
                            display: 'inline-flex',
                            alignItems: 'center',
                            gap: '6px',
                            padding: '8px 12px',
                            borderRadius: '9999px',
                            backgroundColor: '#e2e8f0',
                            color: '#334155',
                            fontSize: '13px',
                            fontWeight: '600',
                            textDecoration: 'none',
                          }}
                        >
                          <Briefcase size={14} />
                          View JD
                        </a>
                      )}
                    </div>
                  )}

                  <p style={{ margin: '0 0 16px 0', fontSize: '14px', lineHeight: 1.6, color: '#475569' }}>
                    {job.description}
                  </p>

                  <div style={{ display: 'flex', gap: '10px', flexWrap: 'wrap' }}>
                    <button
                      type="button"
                      onClick={() => handleToggleJobStatus(job.id, job.status)}
                      style={{
                        ...actionButtonStyle,
                        backgroundColor: isApproved ? '#fee2e2' : '#dcfce7',
                        color: isApproved ? '#b91c1c' : '#166534',
                      }}
                    >
                      {isApproved ? <XCircle size={15} /> : <CheckCircle2 size={15} />}
                      {isApproved ? 'Reject Job' : 'Approve Job'}
                    </button>
                  </div>
                </div>
              );
            })}
          </div>
        </div>
      </div>
    </div>
  );
};

export default Companies;
